<div class="grid grid-2"><div class="card"><h3>Create Payroll Period</h3><form method="post" action="<?=url('/payroll/period')?>"><?=csrf_field()?><div class="form-row"><div><label>Month</label><input name="period_month" type="number" min="1" max="12" required></div><div><label>Year</label><input name="period_year" type="number" required></div></div><div class="form-row"><div><label>Start Date</label><input name="start_date" type="date" required></div><div><label>End Date</label><input name="end_date" type="date" required></div></div><button class="btn btn-primary">Create Period</button></form></div><div class="card"><h3>Run Payroll</h3><form method="post" action="<?=url('/payroll/calculate')?>"><?=csrf_field()?><label>Period</label><select name="period_id"><?php foreach($periods as $p):?><option value="<?=e($p['id'])?>"><?=e($p['period_month'].'/'.$p['period_year'])?> - <?=e($p['status'])?></option><?php endforeach;?></select><br><br><button class="btn btn-primary">Calculate Payroll</button></form></div></div><br><div class="card"><h3>Payroll Runs</h3><table class="table"><tr><th>Run No</th><th>Period</th><th>Gross</th><th>Tax</th><th>Net</th><th>Status</th><th>Action</th></tr><?php foreach($runs as $r):?><tr><td><?=e($r['run_no'])?></td><td><?=e($r['period_month'].'/'.$r['period_year'])?></td><td><?=money_id($r['total_gross'])?></td><td><?=money_id($r['total_tax'])?></td><td><?=money_id($r['total_net'])?></td><td><span class="badge badge-info"><?=e($r['status'])?></span></td><td><form style="display:inline" method="post" action="<?=url('/payroll/approve')?>"><?=csrf_field()?><input type="hidden" name="run_id" value="<?=e($r['id'])?>"><button class="btn btn-light">Approve</button></form> <form style="display:inline" method="post" action="<?=url('/payroll/journal')?>"><?=csrf_field()?><input type="hidden" name="run_id" value="<?=e($r['id'])?>"><button class="btn btn-light">Build Journal</button></form></td></tr><?php endforeach;?></table></div>
